#!/usr/bin/env Rscript
library(rstan)
options(mc.cores = parallel::detectCores())
rstan_options(auto_write = TRUE)

# Load data
data <- read.csv('/app/data.csv')
y <- data$y
n <- data$n
N <- length(y)

# Prepare data for Stan
stan_data <- list(N = N, y = y, n = n)

# Set random seed
set.seed(1)

# Run sampling
fit <- sampling(
  object = stan_model(file = '/app/hierarchical_model.stan'),
  data = stan_data,
  chains = 4,
  iter = 100000,
  seed = 1,
  control = list(adapt_delta = 0.95)
)

# Extract posterior samples
